INSERT INTO journeys (id, province, city, country, date, end_date, title, emoji, description, story, highlights_json, cost_json, photo_url, sort_order) VALUES (1, '欧洲', '法国', '国外', '2026-04-20', '2026-04-23', '法国', '💍', '2026年婚假欧洲之旅，遍历浪漫巴黎、阿尔卑斯雪山、文艺复兴意大利。', '这是人生中最重要的一次旅行，13天的法瑞意深度游。从巴黎的浪漫街头开始，途经瑞士的雪山湖泊，最终抵达意大利的千年古都。每一个城市都留下了属于两个人的足迹。', '["巴黎圣母院、埃菲尔铁塔","塞纳河船餐 、凡尔赛宫","凯旋门、香榭丽舍、蒙马特高地、圣心大教堂","卢浮宫","老佛爷购物"]', '{"package":32149,"transport":0,"accommodation":0,"food":0,"shopping":2098.32,"ticket":0}', NULL, 1);
