INSERT INTO sub_cards (id, journey_id, name, province, city, country, date, end_date, emoji, story, highlights_json, itinerary_table_json, cost_json, photo_url, sort_order) VALUES ('sub-1779521304207', 1, '意大利', '欧洲', '意大利', '国外', '2026-4-26', '2026-5-2', '📍', '', '["米兰大教堂、斯卡拉歌剧院","圣马可广场、贡多拉游船、叹息桥","奥特莱斯","五渔村","比萨斜塔","领主广场、圣母百花大教堂","乌菲兹美术馆","锡耶纳田野广场","皮恩扎奥尔恰山谷","西班牙阶梯、特雷维喷泉、万神殿","斗兽场"]', '{"headers":["日期","上午","下午","备注"],"rows":[["2026-4-26","","米兰大教堂、斯卡拉歌剧院","下午大巴至意大利"],["2026-4-27","圣马可广场、贡多拉游船、叹息桥","奥特莱斯",""],["2026-4-28","五渔村","比萨斜塔",""],["2026-4-29","领主广场、圣母百花大教堂","乌菲兹美术馆",""],["2026-4-30","锡耶纳田野广场","皮恩扎奥尔恰山谷",""],["2026-5-1","西班牙阶梯、特雷维喷泉、万神殿","斗兽场","20:30-12:45 罗马菲乌米奇诺-北京首都"],["2026-5-2","","","中午抵达北京"]]}', '{"package":0,"transport":0,"accommodation":0,"food":0,"shopping":2104,"ticket":0}', NULL, 2);
INSERT INTO journeys (id, province, city, country, date, end_date, title, emoji, description, story, highlights_json, cost_json, photo_url, sort_order) VALUES (2, '福建', '厦门', '中国', '2026-01-15', '2026-01-17', '冬日厦门海滨漫游', '🏝️', '三天两晚厦门之旅，漫步鼓浪屿、环岛路、中山路步行街，感受南方暖冬。', '1月15日早班机抵达厦门，入住中山路步行街附近酒店。第一天逛了中山路、黄厝沙滩和曾厝垵。第二天提前预约了厦门大学，参观了南普陀寺、坐了钟鼓索道、逛了厦门植物园。第三天整天在鼓浪屿，从最美转角到日光岩，最后在八市吃了海鲜。傍晚飞回北京。', '["鼓浪屿","厦门大学","南普陀寺","黄厝沙滩","曾厝垵"]', '{}', NULL, 2);
INSERT INTO sub_cards (id, journey_id, name, province, city, country, date, end_date, emoji, story, highlights_json, itinerary_table_json, cost_json, photo_url, sort_order) VALUES ('sub-2-default', 2, '厦门', '福建', '厦门', '中国', '2026-01-15', '2026-01-17', '🏝️', '1月15日早班机抵达厦门，入住中山路步行街附近酒店。第一天逛了中山路、黄厝沙滩和曾厝垵。第二天提前预约了厦门大学，参观了南普陀寺、坐了钟鼓索道、逛了厦门植物园。第三天整天在鼓浪屿，从最美转角到日光岩，最后在八市吃了海鲜。傍晚飞回北京。', '["鼓浪屿","厦门大学","南普陀寺","黄厝沙滩","曾厝垵"]', '{"headers":["日期","上午","下午","备注"],"rows":[]}', '{}', NULL, 0);
INSERT INTO journeys (id, province, city, country, date, end_date, title, emoji, description, story, highlights_json, cost_json, photo_url, sort_order) VALUES (3, '吉林', '长白山&延吉', '中国', '2025-12-19', '2025-12-21', '冰雪长白山&延吉', '🏔️', '三天东北冰雪之旅，从延吉网红墙到长白山天池，体验朝鲜族风情与雪域奇观。', '12月19日早班机飞抵延吉，打卡网红墙和延边大学，吃了大朴家烤肉。第二天上午逛水上市场和朝鲜民俗园，下午高铁前往长白山，吃了高丽锅。第三天全天长白山北坡游览，天池、瀑布、绿渊潭、谷底森林，晚上高铁回京。原预算6495，实际花费3879，怒省2616！', '["延吉网红墙","朝鲜民俗园","长白山天池","长白山瀑布","绿渊潭"]', '{}', NULL, 3);
INSERT INTO sub_cards (id, journey_id, name, province, city, country, date, end_date, emoji, story, highlights_json, itinerary_table_json, cost_json, photo_url, sort_order) VALUES ('sub-3-default', 3, '长白山&延吉', '吉林', '长白山&延吉', '中国', '2025-12-19', '2025-12-21', '🏔️', '12月19日早班机飞抵延吉，打卡网红墙和延边大学，吃了大朴家烤肉。第二天上午逛水上市场和朝鲜民俗园，下午高铁前往长白山，吃了高丽锅。第三天全天长白山北坡游览，天池、瀑布、绿渊潭、谷底森林，晚上高铁回京。原预算6495，实际花费3879，怒省2616！', '["延吉网红墙","朝鲜民俗园","长白山天池","长白山瀑布","绿渊潭"]', '{"headers":["日期","上午","下午","备注"],"rows":[]}', '{}', NULL, 0);
INSERT INTO journeys (id, province, city, country, date, end_date, title, emoji, description, story, highlights_json, cost_json, photo_url, sort_order) VALUES (4, '辽宁', '沈阳', '中国', '2025-07-05', '2025-07-06', '周末沈阳特种兵', '🛀', '两天一夜沈阳之旅，故宫、大帅府、西塔美食、东北洗浴文化一站式体验。', '7月5日高铁抵达沈阳，先去西塔吃韩国料理，然后逛沈阳故宫和大帅府。晚上体验东北洗浴文化，夜宵吃野人串吧。第二天早起去小河沿早市，吃雪绵豆沙、羊杂汤、肉蛋堡，然后返程回京。', '["沈阳故宫","西塔韩国风情街","东北洗浴","小河沿早市","中街"]', '{}', NULL, 4);
INSERT INTO sub_cards (id, journey_id, name, province, city, country, date, end_date, emoji, story, highlights_json, itinerary_table_json, cost_json, photo_url, sort_order) VALUES ('sub-4-default', 4, '沈阳', '辽宁', '沈阳', '中国', '2025-07-05', '2025-07-06', '🛀', '7月5日高铁抵达沈阳，先去西塔吃韩国料理，然后逛沈阳故宫和大帅府。晚上体验东北洗浴文化，夜宵吃野人串吧。第二天早起去小河沿早市，吃雪绵豆沙、羊杂汤、肉蛋堡，然后返程回京。', '["沈阳故宫","西塔韩国风情街","东北洗浴","小河沿早市","中街"]', '{"headers":["日期","上午","下午","备注"],"rows":[]}', '{}', NULL, 0);
INSERT INTO journeys (id, province, city, country, date, end_date, title, emoji, description, story, highlights_json, cost_json, photo_url, sort_order) VALUES (5, '土耳其', '伊斯坦布尔&卡帕多奇亚', '土耳其', '2025-04-26', '2025-05-05', '星月国奇幻之旅', '🎈', '十天土耳其深度游，热气球、棉花堡、蓝色清真寺，横跨欧亚大陆的浪漫。', '十天的土耳其之旅，从伊斯坦布尔开始，探访蓝色清真寺和圣索菲亚大教堂。飞往卡帕多奇亚乘坐日出热气球，俯瞰精灵烟囱。在棉花堡赤脚走在白色钙华梯田上，最后抵达以弗所触摸古希腊文明的遗迹。', '["卡帕多奇亚热气球","蓝色清真寺","棉花堡","以弗所古城"]', '{}', NULL, 5);
INSERT INTO sub_cards (id, journey_id, name, province, city, country, date, end_date, emoji, story, highlights_json, itinerary_table_json, cost_json, photo_url, sort_order) VALUES ('sub-5-default', 5, '伊斯坦布尔&卡帕多奇亚', '土耳其', '伊斯坦布尔&卡帕多奇亚', '土耳其', '2025-04-26', '2025-05-05', '🎈', '十天的土耳其之旅，从伊斯坦布尔开始，探访蓝色清真寺和圣索菲亚大教堂。飞往卡帕多奇亚乘坐日出热气球，俯瞰精灵烟囱。在棉花堡赤脚走在白色钙华梯田上，最后抵达以弗所触摸古希腊文明的遗迹。', '["卡帕多奇亚热气球","蓝色清真寺","棉花堡","以弗所古城"]', '{"headers":["日期","上午","下午","备注"],"rows":[]}', '{}', NULL, 0);
INSERT INTO journeys (id, province, city, country, date, end_date, title, emoji, description, story, highlights_json, cost_json, photo_url, sort_order) VALUES (6, '广东', '港澳珠', '中国', '2025-04-03', '2025-04-07', '港澳珠大湾区五日游', '🌃', '五天四晚粤港澳之旅，香港迪士尼、澳门大三巴、珠海长隆、港珠澳大桥。', '4月3日飞抵香港，逛旺角、尖沙咀、维多利亚港，晚上入住湾仔。4月4日全天香港迪士尼，从魔雪奇缘世界到灰熊山谷。4月5日上午逛中环铜锣湾，下午经港珠澳大桥坐大巴到珠海，逛圆明新园和日月贝。4月6日澳门一日游，新葡京、大三巴、官也街、威尼斯人。4月7日珠海长隆海洋王国，傍晚飞回北京。合计花费约11868元。', '["香港迪士尼","维多利亚港","澳门大三巴","珠海长隆","港珠澳大桥"]', '{}', NULL, 6);
INSERT INTO sub_cards (id, journey_id, name, province, city, country, date, end_date, emoji, story, highlights_json, itinerary_table_json, cost_json, photo_url, sort_order) VALUES ('sub-6-default', 6, '港澳珠', '广东', '港澳珠', '中国', '2025-04-03', '2025-04-07', '🌃', '4月3日飞抵香港，逛旺角、尖沙咀、维多利亚港，晚上入住湾仔。4月4日全天香港迪士尼，从魔雪奇缘世界到灰熊山谷。4月5日上午逛中环铜锣湾，下午经港珠澳大桥坐大巴到珠海，逛圆明新园和日月贝。4月6日澳门一日游，新葡京、大三巴、官也街、威尼斯人。4月7日珠海长隆海洋王国，傍晚飞回北京。合计花费约11868元。', '["香港迪士尼","维多利亚港","澳门大三巴","珠海长隆","港珠澳大桥"]', '{"headers":["日期","上午","下午","备注"],"rows":[]}', '{}', NULL, 0);
INSERT INTO journeys (id, province, city, country, date, end_date, title, emoji, description, story, highlights_json, cost_json, photo_url, sort_order) VALUES (7, '新疆', '北疆', '中国', '2024-09-30', '2024-10-06', '北疆秋色大环线', '🍂', '七天六晚北疆之旅，天山天池、禾木村、喀纳斯、魔鬼城、赛里木湖。', '国庆期间报团游览北疆大环线。从天池出发，经过布尔津前往禾木村，看晨雾中的图瓦人木屋。喀纳斯湖的碧水倒映着金黄的白桦林。魔鬼城的雅丹地貌在夕阳下如同异域星球。最后一站赛里木湖，大西洋的最后一滴眼泪。', '["天山天池","禾木村","喀纳斯","世界魔鬼城","赛里木湖"]', '{}', NULL, 7);
INSERT INTO sub_cards (id, journey_id, name, province, city, country, date, end_date, emoji, story, highlights_json, itinerary_table_json, cost_json, photo_url, sort_order) VALUES ('sub-7-default', 7, '北疆', '新疆', '北疆', '中国', '2024-09-30', '2024-10-06', '🍂', '国庆期间报团游览北疆大环线。从天池出发，经过布尔津前往禾木村，看晨雾中的图瓦人木屋。喀纳斯湖的碧水倒映着金黄的白桦林。魔鬼城的雅丹地貌在夕阳下如同异域星球。最后一站赛里木湖，大西洋的最后一滴眼泪。', '["天山天池","禾木村","喀纳斯","世界魔鬼城","赛里木湖"]', '{"headers":["日期","上午","下午","备注"],"rows":[]}', '{}', NULL, 0);
INSERT INTO journeys (id, province, city, country, date, end_date, title, emoji, description, story, highlights_json, cost_json, photo_url, sort_order) VALUES (8, '北京', '北京', '中国', '2024-08-24', '2024-08-28', '全家北京深度游', '🏯', '五天四晚带家人游北京，故宫、颐和园、天坛、长城，感受首都的历史与繁华。', '8月24日家人从庆阳坐高铁抵达北京。五天行程满满：第一天吃烤鸭逛天安门王府井；第二天毛主席纪念堂、天安门城楼、故宫、恭王府；第三天清华北大、圆明园、自然博物馆、天坛；第四天电影抓娃娃、颐和园、鸟巢水立方；第五天返程。实际花费约10700元。', '["故宫博物院","颐和园","天坛","恭王府","北海公园"]', '{}', NULL, 8);
INSERT INTO sub_cards (id, journey_id, name, province, city, country, date, end_date, emoji, story, highlights_json, itinerary_table_json, cost_json, photo_url, sort_order) VALUES ('sub-8-default', 8, '北京', '北京', '北京', '中国', '2024-08-24', '2024-08-28', '🏯', '8月24日家人从庆阳坐高铁抵达北京。五天行程满满：第一天吃烤鸭逛天安门王府井；第二天毛主席纪念堂、天安门城楼、故宫、恭王府；第三天清华北大、圆明园、自然博物馆、天坛；第四天电影抓娃娃、颐和园、鸟巢水立方；第五天返程。实际花费约10700元。', '["故宫博物院","颐和园","天坛","恭王府","北海公园"]', '{"headers":["日期","上午","下午","备注"],"rows":[]}', '{}', NULL, 0);
INSERT INTO journeys (id, province, city, country, date, end_date, title, emoji, description, story, highlights_json, cost_json, photo_url, sort_order) VALUES (9, '山东', '青岛', '中国', '2024-06-08', '2024-06-10', '青岛海滨三日游', '🍺', '端午假期青岛之旅，石老人日出、栈桥、八大关、小麦岛、青岛啤酒。', '6月8日晚抵达青岛北站，入住石老人附近。第二天早起看石老人日出，逛栈桥、信号山公园、八大关风景区。晚上在五四广场看灯光秀。第三天去小麦岛，下午参观青岛海洋极地公园，晚上高铁返京。', '["石老人海水浴场","栈桥","八大关","小麦岛","青岛啤酒"]', '{}', NULL, 9);
INSERT INTO sub_cards (id, journey_id, name, province, city, country, date, end_date, emoji, story, highlights_json, itinerary_table_json, cost_json, photo_url, sort_order) VALUES ('sub-9-default', 9, '青岛', '山东', '青岛', '中国', '2024-06-08', '2024-06-10', '🍺', '6月8日晚抵达青岛北站，入住石老人附近。第二天早起看石老人日出，逛栈桥、信号山公园、八大关风景区。晚上在五四广场看灯光秀。第三天去小麦岛，下午参观青岛海洋极地公园，晚上高铁返京。', '["石老人海水浴场","栈桥","八大关","小麦岛","青岛啤酒"]', '{"headers":["日期","上午","下午","备注"],"rows":[]}', '{}', NULL, 0);
INSERT INTO journeys (id, province, city, country, date, end_date, title, emoji, description, story, highlights_json, cost_json, photo_url, sort_order) VALUES (10, '日本', '东京&京都&大阪', '日本', '2024-04-27', '2024-05-03', '五一日本赏樱之旅', '🌸', '黄金周日本七日游，东京、京都、大阪，正值樱花季尾声。', '五一黄金周日本之旅。东京的繁华与京都的古朴形成鲜明对比。在清水寺看日落，在伏见稻荷大社穿越千本鸟居，在岚山竹林感受宁静。最后在大阪道顿堀大快朵颐，去奈良和小鹿互动。', '["清水寺","伏见稻荷大社","岚山竹林","大阪城","奈良公园"]', '{}', NULL, 10);
INSERT INTO sub_cards (id, journey_id, name, province, city, country, date, end_date, emoji, story, highlights_json, itinerary_table_json, cost_json, photo_url, sort_order) VALUES ('sub-10-default', 10, '东京&京都&大阪', '日本', '东京&京都&大阪', '日本', '2024-04-27', '2024-05-03', '🌸', '五一黄金周日本之旅。东京的繁华与京都的古朴形成鲜明对比。在清水寺看日落，在伏见稻荷大社穿越千本鸟居，在岚山竹林感受宁静。最后在大阪道顿堀大快朵颐，去奈良和小鹿互动。', '["清水寺","伏见稻荷大社","岚山竹林","大阪城","奈良公园"]', '{"headers":["日期","上午","下午","备注"],"rows":[]}', '{}', NULL, 0);
INSERT INTO journeys (id, province, city, country, date, end_date, title, emoji, description, story, highlights_json, cost_json, photo_url, sort_order) VALUES (11, '山西', '大同', '中国', '2024-04-04', '2024-04-06', '清明大同古建巡礼', '🗿', '三天两晚山西大同之旅，云冈石窟、应县木塔、悬空寺、恒山、大同古城。', '清明假期自驾/高铁前往大同。第一天游览云冈石窟，看千年佛像。第二天应县木塔、悬空寺、恒山一日游。第三天逛大同古城，吃凯鸽酒楼、抿八股、压豆面。', '["云冈石窟","应县木塔","悬空寺","恒山","大同古城"]', '{}', NULL, 11);
INSERT INTO sub_cards (id, journey_id, name, province, city, country, date, end_date, emoji, story, highlights_json, itinerary_table_json, cost_json, photo_url, sort_order) VALUES ('sub-11-default', 11, '大同', '山西', '大同', '中国', '2024-04-04', '2024-04-06', '🗿', '清明假期自驾/高铁前往大同。第一天游览云冈石窟，看千年佛像。第二天应县木塔、悬空寺、恒山一日游。第三天逛大同古城，吃凯鸽酒楼、抿八股、压豆面。', '["云冈石窟","应县木塔","悬空寺","恒山","大同古城"]', '{"headers":["日期","上午","下午","备注"],"rows":[]}', '{}', NULL, 0);
INSERT INTO journeys (id, province, city, country, date, end_date, title, emoji, description, story, highlights_json, cost_json, photo_url, sort_order) VALUES (12, '黑龙江', '哈尔滨', '中国', '2023-12-30', '2024-01-01', '跨年冰雪哈尔滨', '❄️', '元旦三天哈尔滨之旅，冰雪大世界、中央大街、索菲亚大教堂、东北铁锅炖。', '12月30日高铁抵达哈尔滨，晚上吃山河屯铁锅炖，逛中央大街吃糖葫芦，走到防洪纪念塔看松花江。12月31日全天冰雪大世界，晚上跨年。1月1日上午参观索菲亚大教堂，中午吃牛蛙锅，然后返程。必备暖宝宝、墨镜、棉裤、棉鞋！', '["冰雪大世界","中央大街","索菲亚大教堂","松花江","东北洗浴"]', '{}', NULL, 12);
INSERT INTO sub_cards (id, journey_id, name, province, city, country, date, end_date, emoji, story, highlights_json, itinerary_table_json, cost_json, photo_url, sort_order) VALUES ('sub-12-default', 12, '哈尔滨', '黑龙江', '哈尔滨', '中国', '2023-12-30', '2024-01-01', '❄️', '12月30日高铁抵达哈尔滨，晚上吃山河屯铁锅炖，逛中央大街吃糖葫芦，走到防洪纪念塔看松花江。12月31日全天冰雪大世界，晚上跨年。1月1日上午参观索菲亚大教堂，中午吃牛蛙锅，然后返程。必备暖宝宝、墨镜、棉裤、棉鞋！', '["冰雪大世界","中央大街","索菲亚大教堂","松花江","东北洗浴"]', '{"headers":["日期","上午","下午","备注"],"rows":[]}', '{}', NULL, 0);
INSERT INTO journeys (id, province, city, country, date, end_date, title, emoji, description, story, highlights_json, cost_json, photo_url, sort_order) VALUES (13, '安徽&上海', '黄山&上海', '中国', '2023-09-29', '2023-10-05', '国庆黄山上海七日游', '⛰️', '国庆假期婺源篁岭、宏村、黄山、上海七日游，从徽派古村到魔都繁华。', '9月29日高铁到婺源，游篁岭看晒秋。30日前往宏村，水墨徽派建筑。10月1日爬黄山，奇松怪石云海。10月2日下山高铁到上海。10月3日武康路、新天地、豫园、外滩、陆家嘴。10月4日人民广场、外白渡桥、1933老场坊。10月5日返程。预算5600元。', '["婺源篁岭","宏村","黄山","外滩","武康路"]', '{}', NULL, 13);
INSERT INTO sub_cards (id, journey_id, name, province, city, country, date, end_date, emoji, story, highlights_json, itinerary_table_json, cost_json, photo_url, sort_order) VALUES ('sub-13-default', 13, '黄山&上海', '安徽&上海', '黄山&上海', '中国', '2023-09-29', '2023-10-05', '⛰️', '9月29日高铁到婺源，游篁岭看晒秋。30日前往宏村，水墨徽派建筑。10月1日爬黄山，奇松怪石云海。10月2日下山高铁到上海。10月3日武康路、新天地、豫园、外滩、陆家嘴。10月4日人民广场、外白渡桥、1933老场坊。10月5日返程。预算5600元。', '["婺源篁岭","宏村","黄山","外滩","武康路"]', '{"headers":["日期","上午","下午","备注"],"rows":[]}', '{}', NULL, 0);
INSERT INTO journeys (id, province, city, country, date, end_date, title, emoji, description, story, highlights_json, cost_json, photo_url, sort_order) VALUES (14, '辽宁', '大连', '中国', '2023-06-22', '2023-06-24', '端午大连看海', '🌊', '三天大连海滨之旅，棒棰岛、星海广场、东方威尼斯水城、海鲜大餐。', '端午节大连三日游。第一天东港音乐喷泉广场和威尼斯水城夜景。第二天棒棰岛看日出，渔人码头、菱角湾、黑石礁、星海公园、星海广场。第三天银沙滩。吃了日月昇海鲜码头、钱库里海鲜自助，实现海鲜自由。', '["棒棰岛","星海广场","东方威尼斯水城","东港音乐喷泉","菱角湾"]', '{}', NULL, 14);
INSERT INTO sub_cards (id, journey_id, name, province, city, country, date, end_date, emoji, story, highlights_json, itinerary_table_json, cost_json, photo_url, sort_order) VALUES ('sub-14-default', 14, '大连', '辽宁', '大连', '中国', '2023-06-22', '2023-06-24', '🌊', '端午节大连三日游。第一天东港音乐喷泉广场和威尼斯水城夜景。第二天棒棰岛看日出，渔人码头、菱角湾、黑石礁、星海公园、星海广场。第三天银沙滩。吃了日月昇海鲜码头、钱库里海鲜自助，实现海鲜自由。', '["棒棰岛","星海广场","东方威尼斯水城","东港音乐喷泉","菱角湾"]', '{"headers":["日期","上午","下午","备注"],"rows":[]}', '{}', NULL, 0);
INSERT INTO journeys (id, province, city, country, date, end_date, title, emoji, description, story, highlights_json, cost_json, photo_url, sort_order) VALUES (15, '山东', '泰山&济南', '中国', '2023-05-20', '2023-05-21', '520泰山夜爬之旅', '🌄', '周末泰山济南两日游，夜爬泰山看日出，济南趵突泉大明湖逛老城。', '5月20日周六，北京站坐夜车硬卧到泰山站。天外村坐大巴到中天门，再徒步3小时到南天门、玉皇顶。下山坐桃花源索道。下午高铁到济南。晚上吃烧烤。第二天逛趵突泉、黑虎泉、大明湖、超然楼、曲水亭街、宽厚里，吃把子肉，晚高铁返京。', '["泰山日出","趵突泉","大明湖","超然楼","芙蓉街"]', '{}', NULL, 15);
INSERT INTO sub_cards (id, journey_id, name, province, city, country, date, end_date, emoji, story, highlights_json, itinerary_table_json, cost_json, photo_url, sort_order) VALUES ('sub-15-default', 15, '泰山&济南', '山东', '泰山&济南', '中国', '2023-05-20', '2023-05-21', '🌄', '5月20日周六，北京站坐夜车硬卧到泰山站。天外村坐大巴到中天门，再徒步3小时到南天门、玉皇顶。下山坐桃花源索道。下午高铁到济南。晚上吃烧烤。第二天逛趵突泉、黑虎泉、大明湖、超然楼、曲水亭街、宽厚里，吃把子肉，晚高铁返京。', '["泰山日出","趵突泉","大明湖","超然楼","芙蓉街"]', '{"headers":["日期","上午","下午","备注"],"rows":[]}', '{}', NULL, 0);
INSERT INTO journeys (id, province, city, country, date, end_date, title, emoji, description, story, highlights_json, cost_json, photo_url, sort_order) VALUES (16, '湖南', '长沙&张家界', '中国', '2022-10-01', '2022-10-06', '国庆长沙张家界极限跑毒', '😷', '国庆六日游长沙张家界，经历黄码申诉、武陵源封控、极限买机票返京的难忘旅程。', '10月1日到长沙，橘子洲头、五一广场、太平街，喝茶颜悦色。10月2日岳麓山、岳麓书院、文和友。10月3日高铁到张家界，黄龙洞。10月4日张家界国家森林公园。10月5日一觉醒来武陵源黄码，申诉后转绿，发现北京健康宝弹窗。10月6日武陵源封控，极限刷到下午4点45的机票，坐摩托赶到机场，登机前收到红头文件发现阳性。一环扣一环，极限跑毒保住绿码！', '["橘子洲头","岳麓书院","张家界国家森林公园","黄龙洞","茶颜悦色"]', '{}', NULL, 16);
INSERT INTO sub_cards (id, journey_id, name, province, city, country, date, end_date, emoji, story, highlights_json, itinerary_table_json, cost_json, photo_url, sort_order) VALUES ('sub-16-default', 16, '长沙&张家界', '湖南', '长沙&张家界', '中国', '2022-10-01', '2022-10-06', '😷', '10月1日到长沙，橘子洲头、五一广场、太平街，喝茶颜悦色。10月2日岳麓山、岳麓书院、文和友。10月3日高铁到张家界，黄龙洞。10月4日张家界国家森林公园。10月5日一觉醒来武陵源黄码，申诉后转绿，发现北京健康宝弹窗。10月6日武陵源封控，极限刷到下午4点45的机票，坐摩托赶到机场，登机前收到红头文件发现阳性。一环扣一环，极限跑毒保住绿码！', '["橘子洲头","岳麓书院","张家界国家森林公园","黄龙洞","茶颜悦色"]', '{"headers":["日期","上午","下午","备注"],"rows":[]}', '{}', NULL, 0);
INSERT INTO journeys (id, province, city, country, date, end_date, title, emoji, description, story, highlights_json, cost_json, photo_url, sort_order) VALUES (17, '四川&重庆', '成都&重庆', '中国', '2023-09-29', '2023-10-04', '川渝六日美食之旅', '🐼', '国庆成都重庆六日游，大熊猫、火锅、洪崖洞、李子坝，吃遍川渝美食。', '9月29日高铁到成都，春熙路太古里。30日人民公园、成都博物馆、宽窄巷子、文殊院。10月1日大熊猫基地、杜甫草堂、武侯祠、锦里。10月2日高铁到重庆，解放碑、洪崖洞、千厮门大桥。10月3日李子坝、重庆动物园。10月4日返程。吃了火锅、兔头、烤苕皮、钵钵鸡、重庆小面。', '["大熊猫基地","宽窄巷子","洪崖洞","李子坝","长江索道"]', '{}', NULL, 17);
INSERT INTO sub_cards (id, journey_id, name, province, city, country, date, end_date, emoji, story, highlights_json, itinerary_table_json, cost_json, photo_url, sort_order) VALUES ('sub-17-default', 17, '成都&重庆', '四川&重庆', '成都&重庆', '中国', '2023-09-29', '2023-10-04', '🐼', '9月29日高铁到成都，春熙路太古里。30日人民公园、成都博物馆、宽窄巷子、文殊院。10月1日大熊猫基地、杜甫草堂、武侯祠、锦里。10月2日高铁到重庆，解放碑、洪崖洞、千厮门大桥。10月3日李子坝、重庆动物园。10月4日返程。吃了火锅、兔头、烤苕皮、钵钵鸡、重庆小面。', '["大熊猫基地","宽窄巷子","洪崖洞","李子坝","长江索道"]', '{"headers":["日期","上午","下午","备注"],"rows":[]}', '{}', NULL, 0);
INSERT INTO journeys (id, province, city, country, date, end_date, title, emoji, description, story, highlights_json, cost_json, photo_url, sort_order) VALUES (18, '江苏', '苏州&南京', '中国', '2021-09-30', '2021-10-04', '江南五日游', '🎋', '国庆苏州南京五日游，拙政园、平江路、秦淮河、夫子庙，体验江南水乡。', '9月30日北京到苏州，逛观前街。10月1日苏州博物馆、拙政园、平江路、山塘街。10月2日同里古镇。10月3日寒山寺、淮海街，下午高铁到南京，晚上秦淮河夫子庙。10月4日鸡鸣寺、玄武湖、明城墙、老门东，晚上返京。吃了苏州太太苏帮菜、桃花源记醉蟹、南京大牌档。', '["拙政园","平江路","山塘街","秦淮河","鸡鸣寺"]', '{}', NULL, 18);
INSERT INTO sub_cards (id, journey_id, name, province, city, country, date, end_date, emoji, story, highlights_json, itinerary_table_json, cost_json, photo_url, sort_order) VALUES ('sub-18-default', 18, '苏州&南京', '江苏', '苏州&南京', '中国', '2021-09-30', '2021-10-04', '🎋', '9月30日北京到苏州，逛观前街。10月1日苏州博物馆、拙政园、平江路、山塘街。10月2日同里古镇。10月3日寒山寺、淮海街，下午高铁到南京，晚上秦淮河夫子庙。10月4日鸡鸣寺、玄武湖、明城墙、老门东，晚上返京。吃了苏州太太苏帮菜、桃花源记醉蟹、南京大牌档。', '["拙政园","平江路","山塘街","秦淮河","鸡鸣寺"]', '{"headers":["日期","上午","下午","备注"],"rows":[]}', '{}', NULL, 0);
INSERT INTO journeys (id, province, city, country, date, end_date, title, emoji, description, story, highlights_json, cost_json, photo_url, sort_order) VALUES (19, '陕西', '西安', '中国', '2019-04-05', '2019-04-07', '古都西安文化之旅', '🏛️', '多次探访西安，大明宫、回民街、永兴坊、大唐不夜城、兵马俑。', '从2016到2019多次前往西安。第一次是大明宫和牛羊肉泡馍。后来陆续去了西安博物馆、永兴坊、大唐不夜城。每次去回民街都会吃串、魏家凉皮，看完电影吃海底捞。西安是一座每次去都有新发现的城市。', '["大唐不夜城","回民街","永兴坊","牛羊肉泡馍"]', '{}', NULL, 19);
INSERT INTO sub_cards (id, journey_id, name, province, city, country, date, end_date, emoji, story, highlights_json, itinerary_table_json, cost_json, photo_url, sort_order) VALUES ('sub-19-default', 19, '西安', '陕西', '西安', '中国', '2019-04-05', '2019-04-07', '🏛️', '从2016到2019多次前往西安。第一次是大明宫和牛羊肉泡馍。后来陆续去了西安博物馆、永兴坊、大唐不夜城。每次去回民街都会吃串、魏家凉皮，看完电影吃海底捞。西安是一座每次去都有新发现的城市。', '["大唐不夜城","回民街","永兴坊","牛羊肉泡馍"]', '{"headers":["日期","上午","下午","备注"],"rows":[]}', '{}', NULL, 0);
INSERT INTO journeys (id, province, city, country, date, end_date, title, emoji, description, story, highlights_json, cost_json, photo_url, sort_order) VALUES (20, '北京', '北京', '中国', '2019-02-01', '2025-12-13', '北京游记（2019-2025）', '🦆', '常年居住北京，周末和假期探索首都的每一个角落，从故宫到奥森，从演唱会到公园。', '在北京生活多年，利用周末和假期探索了几乎所有知名景点。2019年天安门、中山公园、动物园。2021年故宫、颐和园、玉渊潭。2022年圆明园、北海公园、香山、黄花城水长城。2023年环球影城、居庸关长城、野生动物园、鸟巢薛之谦演唱会。2024年全家游、邓紫棋/张杰/许嵩演唱会、八达岭长城。2025年地坛公园、雍和宫、朝阳公园、欢乐谷、密云水库、野鸭湖、景山公园。', '["故宫","颐和园","环球影城","鸟巢演唱会","奥森公园"]', '{}', NULL, 20);
