INSERT INTO journeys (id, province, city, country, date, end_date, title, emoji, description, story, highlights_json, cost_json, photo_url, sort_order) VALUES (21, '河北', '秦皇岛', '中国', '2020-10-02', '2020-10-05', '国庆秦皇岛看海', '🦀', '四天三晚秦皇岛之旅，鸽子窝日出、野生动物园、碧螺岛、海鲜大餐。', '2020年国庆去秦皇岛，住在庆山饭店。早起去鸽子窝公园看日出，白天逛野生动物园，晚上在碧螺岛海上酒吧。吃了秦皇小巷和燕大夜市，还有大锅蒸海鲜。', '["鸽子窝公园","秦皇岛野生动物园","碧螺岛","秦皇小巷","蒸海鲜"]', '{}', NULL, 21);
INSERT INTO sub_cards (id, journey_id, name, province, city, country, date, end_date, emoji, story, highlights_json, itinerary_table_json, cost_json, photo_url, sort_order) VALUES ('sub-21-default', 21, '秦皇岛', '河北', '秦皇岛', '中国', '2020-10-02', '2020-10-05', '🦀', '2020年国庆去秦皇岛，住在庆山饭店。早起去鸽子窝公园看日出，白天逛野生动物园，晚上在碧螺岛海上酒吧。吃了秦皇小巷和燕大夜市，还有大锅蒸海鲜。', '["鸽子窝公园","秦皇岛野生动物园","碧螺岛","秦皇小巷","蒸海鲜"]', '{"headers":["日期","上午","下午","备注"],"rows":[]}', '{}', NULL, 0);
INSERT INTO journeys (id, province, city, country, date, end_date, title, emoji, description, story, highlights_json, cost_json, photo_url, sort_order) VALUES (22, '天津', '天津', '中国', '2019-02-01', '2025-06-22', '天津多次游览', '🎡', '多次前往天津，意大利风情区、天津之眼、海河游船、极地海洋公园、玛雅水上乐园。', '2019年2月第一次去天津，逛津门故里、意大利风情区、天津之眼、海河。2019年9月去天津海昌极地海洋公园。2021年6月意大利风情区、天津之眼、游船、玛雅海滩水公园。2025年6月再次去玛雅水上乐园。', '["天津之眼","意大利风情区","海河游船","极地海洋公园","玛雅海滩水公园"]', '{}', NULL, 22);
