INSERT INTO journeys (id, province, city, country, date, end_date, title, emoji, description, story, highlights_json, cost_json, photo_url, sort_order) VALUES (23, '辽宁&山东', '大连&威海', '中国', '2023-06-22', '2023-06-25', '大连威海四日游', '🚢', '大连威海四日游，菱角湾、棒棰岛、跨海轮渡海上日出、威海海岸线。', '第一天黑石礁、星海公园、星海广场、银沙滩。第二天菱角湾、虎滩公园、渔人码头、棒棰岛、威尼斯水城、东港喷泉，晚上大连港坐轮渡到威海（卧铺，海上日出）。第三天威海港、悦海公园灯塔、大相框、幸福门、半月湾、猫头山、火炬八街。', '["棒棰岛","菱角湾","海上轮渡日出","火炬八街","猫头山"]', '{}', NULL, 23);
