INSERT INTO journeys (id, province, city, country, date, end_date, title, emoji, description, story, highlights_json, cost_json, photo_url, sort_order) VALUES (24, '甘肃', '兰州', '中国', '2018-01-01', '2018-01-01', '兰州美食之旅', '🍜', '兰州多次游览，中山桥、白塔山、黄河、甘肃省博物馆、牛肉面。', '多次去兰州，逛中山桥、白塔山、五泉山，在黄河边喝茶。参观甘肃省博物馆看马踏飞燕。吃正宗兰州牛肉面、羊杂碎。还去了兰山公园看夜景。', '["中山桥","白塔山","甘肃省博物馆","黄河","兰州牛肉面"]', '{}', NULL, 24);
